import { readFile } from "node:fs/promises";
import path from "node:path";

const htmlFiles = {
  commandCenter: path.join(/*turbopackIgnore: true*/ process.cwd(), "immuvi-command-center.html"),
  commandCenterV2: path.join(/*turbopackIgnore: true*/ process.cwd(), "immuvi-command-center-v2.html"),
  actionPlanLive: path.join(/*turbopackIgnore: true*/ process.cwd(), "action-plan-live.html")
};

export type LegacyHtmlFile = keyof typeof htmlFiles;

export async function legacyHtmlResponse(file: LegacyHtmlFile) {
  const htmlPath = htmlFiles[file];
  const html = await readFile(htmlPath, "utf8");

  return new Response(html, {
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "no-store"
    }
  });
}
